"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";

export default function CategoryFilter({ category }) {
  const [selected, setSelected] = useState([]);
  const router = useRouter();

  // Handle checkbox toggle
  const handleChange = (slug) => {
    setSelected((prev) =>
      prev.includes(slug)
        ? prev.filter((item) => item !== slug)
        : [...prev, slug]
    );
  };

  // Apply filter (on confirm)
  const handleApply = () => {
    if (selected.length === 0) return;

    // Example: /products?category=men,shoes
    const query = selected.join(",");
    router.push(`/products/${query}`);
  };

  return (
    <div className="w-72 bg-gray-200 rounded-md p-4">
      
      {/* Header */}
      <h2 className="text-sm font-semibold text-gray-700 mb-3 tracking-wide">
        CATEGORIES
      </h2>

      {/* All Categories */}
      <button
        onClick={() => {
          setSelected([]);
          router.push("/products");
        }}
        className="w-full cursor-pointer mb-4 py-2 text-sm font-medium bg-white rounded-lg border hover:bg-gray-50 transition"
      >
        All Categories
      </button>

      {/* Section Title */}
      <h3 className="text-sm font-semibold text-gray-800 mb-2 ps-2">
        Filter Category
      </h3>

      {/* Category List */}
      <div className="max-h-80 overflow-y-auto space-y-1 pr-1">
        {category.map((item) => (
          <label
            key={item._id}
            className="flex items-center gap-2 px-2 py-1.5 rounded-md cursor-pointer hover:bg-white transition group"
          >
            <input
              type="checkbox"
              checked={selected.includes(item.slug)}
              onChange={() => handleChange(item.slug)}
              className="w-4 h-4 accent-black cursor-pointer"
            />

            <span className="text-sm text-gray-700 group-hover:text-black">
              {item.name}
            </span>
          </label>
        ))}
      </div>

      {/* Confirm Button (only shows if something selected) */}
      {selected.length > 0 && (
        <button
          onClick={handleApply}
          className="mt-4 w-full py-2 bg-black text-white text-sm rounded-lg hover:bg-gray-800 transition"
        >
          Apply Filter
        </button>
      )}
    </div>
  );
}

