'use client'

import { useSearchParams,useRouter } from "next/navigation";
import { useRouter } from "next/router";

export default function BrandFilter({brand}) {
  const router = useRouter()
  const search_params = useSearchParams();
  const salect_brand = search_params.get("brand_slug") 
  // console.log(salect_brand)
  function filterHandler(slug) {
    const query = new URLSearchParams(search_params.toString())
    if(slug === salect_brand){
      query.delete("brand_slug")
    } else{
      query.set("brand_slug", slug);
    }
    router.push(`/products?${query.toString()}`);
    console.log(query)
  }

    return (
      <div className="w-72 bg-gray-200 rounded-md p-4 mt-3 ">
        
        {/* Title */}
        <h2 className="text-sm font-semibold text-gray-800 mb-4">
          By Brands
        </h2>
  
        {/* Search Input */}
        <input
          type="text"
          placeholder=""
          className="w-full mb-4 px-3 py-2 rounded-lg border border-gray-200 bg-white focus:outline-none focus:ring-1 focus:ring-gray-300"
        />
  
        {/* Brand List */}
        <div className="space-y-2">
          {brand.map((brand, i) => (
            <label
              key={i}
              className="flex items-center justify-between px-2 py-1.5 rounded-md cursor-pointer hover:bg-white transition group"
            >
              <div className="flex items-center gap-2">
                <input
                  type="checkbox"
                  className="w-4 h-4 accent-gray-700 cursor-pointer"
                />
  
                {/* Fake logo circle */}
                <div className="w-5 h-5 rounded-full bg-gray-300 flex items-center justify-center text-[10px] font-semibold text-white">
                  {brand.name.charAt(0).toUpperCase()}
                </div>
  
                <span onClick={()=>filterHandler(brand.slug)} className="text-sm text-gray-700 group-hover:text-black capitalize">
                  {brand.name}
                </span>
              </div>
  
              <span className="text-sm text-gray-400">
                ({brand.count})
              </span>
            </label>
          ))}
        </div>
      </div>
    );
  }